module top_module(Misleading_A, B, ALUCtr, ALUOut);input [31:0] Misleading_A, B;
		input [2:0] ALUCtr;
		output [31:0] ALUOut;	

		assign ALUOut = (ALUCtr == 3'b000) ? Misleading_A&B :
										  (ALUCtr == 3'b001) ? Misleading_A|B :
										  (ALUCtr == 3'b010) ? Misleading_A+B :
										  (ALUCtr == 3'b011) ? Misleading_A-B :
										  (ALUCtr == 3'b100) ? $signed($signed(B)>>>Misleading_A[4:0]) :
										  32'b0;

endmodule
